const productos=$('Parsear Input').first().json.productos||[];
const personalId=$vars.PCH_PERSONAL_ID;
const h1=$vars.PCH_HEADER_1;const h2=$vars.PCH_HEADER_2;const h3=$vars.PCH_HEADER_3;
const allResults=[];
for(const p of productos){
  try{
    const resp=await $helpers.httpRequest({method:'GET',url:'https://shop.pchconnect.com/api/products/search',headers:{'X-Personal-ID':personalId,'X-Header-1':h1,'X-Header-2':h2,'X-Header-3':h3,'Content-Type':'application/json'},qs:{q:p.searchQuery,limit:5}});
    const items=resp.products||resp.items||resp.data||[];
    for(const item of (Array.isArray(items)?items:[]).slice(0,3)){
      allResults.push({mayorista:'PCH Connect',sku:item.sku||item.partNumber||'',skuFabricante:item.manufacturerPartNumber||'',descripcion:item.description||item.name||'',marca:item.brand||p.marca,precio:Number(item.price||item.unitPrice||0),moneda:'MXN',existencia:Number(item.stock||item.quantityAvailable||0),disponible:(item.stock||0)>0,imagenUrl:item.imageUrl||'',productoBuscado:p.searchQuery});
    }
  }catch(e){allResults.push({mayorista:'PCH Connect',error:e.message,productoBuscado:p.searchQuery});}
}
return allResults.map(r=>({json:r}));
